314→async function runSingleUpload(
315→	flags: UploadFlags,
316→	session: string,
317→): Promise<void> {
318→	const write = (msg: string) => {
319→		process.stdout.write(`${msg}\n`);
320→	};
321→	const writeError = (msg: string) => {
322→		process.stderr.write(`${msg}\n`);
323→	};
324→
325→	const credentials = loadCredentials();
326→	if (!credentials && !flags.dryRun) {
327→		writeError("Error: Not authenticated. Run `rudel login` first.");
328→		process.exitCode = 1;
329→		return;
330→	}
331→
332→	write(`Resolving session: ${session}`);
333→	let sessionInfo: Awaited<ReturnType<typeof resolveSession>>;
334→	try {
335→		sessionInfo = await resolveSession(session);
336→	} catch (error) {
337→		writeError(
338→			`Error: ${error instanceof Error ? error.message : String(error)}`,
339→		);
340→		process.exitCode = 1;
341→		return;
342→	}
343→	write(`Found session at: ${sessionInfo.transcriptPath}`);
344→
345→	write("Reading transcript...");
346→	let content: string;
347→	try {
348→		content = await readTranscript(sessionInfo.transcriptPath);
349→	} catch (error) {
350→		writeError(
351→			`Error reading transcript: ${error instanceof Error ? error.message : String(error)}`,
352→		);
353→		process.exitCode = 1;
354→		return;
355→	}
356→	write(`Transcript: ${content.length} bytes`);
357→
358→	const agentIds = extractAgentIds(content);
359→	let subagents: SubagentFile[] = [];
360→	if (agentIds.length > 0) {
361→		write(`Found ${agentIds.length} subagent(s): ${agentIds.join(", ")}`);
362→		subagents = await readSubagentFiles(
363→			sessionInfo.sessionDir,
364→			agentIds,
365→			sessionInfo.sessionId,
366→		);
367→		write(
368→			`Read ${subagents.length} subagent file(s): ${subagents.reduce((sum, s) => sum + s.content.length, 0)} bytes total`,
369→		);
370→	}
371→
372→	const gitInfo = await getGitInfo(sessionInfo.projectPath);
373→	if (gitInfo.repository) write(`Repository: ${gitInfo.repository}`);
374→	if (gitInfo.branch) write(`Branch: ${gitInfo.branch}`);
375→
376→	let tag = flags.tag;
377→	if (!tag && flags.classify) {
378→		write("Classifying session...");
379→		tag = (await classifySession(content)) ?? undefined;
380→		if (tag) write(`Classified as: ${tag}`);
381→	}
382→
383→	const organizationId =
384→		flags.org ?? (await getProjectOrgId(sessionInfo.projectPath));
385→	if (organizationId) write(`Organization: ${organizationId}`);
386→
387→	const request: IngestRequest = {
388→		sessionId: sessionInfo.sessionId,
389→		projectPath: sessionInfo.projectPath,
390→		repository: gitInfo.repository,
391→		gitRemote: gitInfo.gitRemote,
392→		packageName: gitInfo.packageName,
393→		gitBranch: gitInfo.branch,
394→		gitSha: gitInfo.sha,
395→		tag,
396→		content,
397→		subagents: subagents.length > 0 ? subagents : undefined,
398→		organizationId,
399→	};
400→
401→	if (flags.dryRun) {
402→		const preview = {
403→			...request,
404→			content: `[${request.content.length} bytes]`,
405→			subagents: request.subagents?.map((s) => ({
406→				...s,
407→				content: `[${s.content.length} bytes]`,
408→			})),
409→		};
