125→	for (const adapter of adaptersToEnable) {
126→		const sessions = await adapter.findProjectSessions(cwd);
127→		if (sessions.length === 0) continue;
128→
129→		const shouldUpload = await p.confirm({
130→			message: `Found ${sessions.length} previous ${adapter.name} session(s). Upload them now?`,
131→			initialValue: false,
132→		});
133→
134→		if (p.isCancel(shouldUpload) || !shouldUpload) continue;
135→
136→		const gitInfo = await getGitInfo(cwd);
137→		let failed = 0;
138→
139→		await p.tasks(
140→			sessions.map((session, i) => ({
141→				title: `[${i + 1}/${sessions.length}] ${session.sessionId}`,
142→				task: async (message: (msg: string) => void) => {
143→					try {
144→						message("Building upload request...");
145→						const request = await adapter.buildUploadRequest(session, {
146→							gitInfo,
147→							organizationId: selectedOrgId,
148→						});
149→
150→						message("Uploading...");
151→						const result = await uploadSession(request, {
152→							endpoint,
153→							token: credentials.token,
154→						});
155→
156→						if (result.success) return "Uploaded";
157→						failed++;
158→						return `Failed: ${result.error}`;
159→					} catch (error) {
160→						failed++;
161→						return `Error: ${error instanceof Error ? error.message : String(error)}`;
162→					}
163→				},
164→			})),
165→		);
166→
167→		if (failed > 0) {
168→			p.log.error(`${failed} ${adapter.name} session(s) failed`);
169→			totalFailed += failed;
170→		}
171→	}
172→
173→	p.outro("Done!");
174→
175→	if (totalFailed > 0) {
176→		process.exitCode = 1;
177→	}
