  2→import type { ScannedProject, SessionFile } from "@rudel/agent-adapters";
  3→import { getGitRemoteUrl, normalizeRemoteUrl } from "./git-info.js";
  4→import {
  5→	cacheRemote,
  6→	cacheRemotes,
  7→	getCachedRemote,
  8→	getRemoteCache,
  9→} from "./remote-cache.js";
 10→
 11→export interface ProjectGroup {
 12→	displayName: string;
 13→	gitRemote: string | null;
 14→	projects: ScannedProject[];
 15→	totalSessions: number;
 16→	containsCwd: boolean;
 17→}
 18→
 19→function extractDisplayName(normalized: string): string {
 20→	// "github.com/owner/repo" → "owner/repo"
 21→	const parts = normalized.split("/");
 22→	if (parts.length >= 3) {
 23→		return parts.slice(1).join("/");
 24→	}
 25→	return normalized;
 26→}
 27→
 28→function encodeProjectPath(projectPath: string): string {
 29→	return projectPath.replace(/\//g, "-");
 30→}
 31→
 32→export async function groupProjectsByRemote(
 33→	projects: ScannedProject[],
 34→	cwd: string,
 35→): Promise<ProjectGroup[]> {
 36→	const cache = await getRemoteCache();
 37→	let cacheUpdated = false;
 38→
 39→	const remotes = await Promise.all(
 40→		projects.map((p) => getGitRemoteUrl(p.projectPath)),
 41→	);
 42→
 43→	const grouped = new Map<
 44→		string,
 45→		{ remote: string; projects: ScannedProject[] }
 46→	>();
 47→	const ungrouped: ScannedProject[] = [];
 48→
 49→	for (let i = 0; i < projects.length; i++) {
 50→		const project = projects[i] as ScannedProject;
 51→		const remote = remotes[i];
 52→
 53→		if (remote) {
 54→			const normalized = normalizeRemoteUrl(remote);
 55→			const encodedDir = encodeProjectPath(project.projectPath);
 56→			// Cache newly resolved remotes
 57→			if (getCachedRemote(cache, encodedDir) !== normalized) {
 58→				cacheRemote(cache, encodedDir, normalized);
 59→				cacheUpdated = true;
 60→			}
 61→			const existing = grouped.get(normalized);
 62→			if (existing) {
 63→				existing.projects.push(project);
 64→			} else {
 65→				grouped.set(normalized, { remote: normalized, projects: [project] });
 66→			}
 67→		} else {
 68→			// Try cache for ungrouped projects
 69→			const encodedDir = encodeProjectPath(project.projectPath);
 70→			const cached = getCachedRemote(cache, encodedDir);
 71→			if (cached) {
 72→				const existing = grouped.get(cached);
 73→				if (existing) {
 74→					existing.projects.push(project);
 75→				} else {
 76→					grouped.set(cached, { remote: cached, projects: [project] });
 77→				}
 78→			} else {
 79→				ungrouped.push(project);
 80→			}
 81→		}
 82→	}
 83→
 84→	const groups: ProjectGroup[] = [];
 85→
 86→	for (const [, entry] of grouped) {
 87→		const containsCwd = entry.projects.some(
 88→			(p) => cwd === p.projectPath || cwd.startsWith(`${p.projectPath}/`),
 89→		);
 90→		groups.push({
 91→			displayName: extractDisplayName(entry.remote),
 92→			gitRemote: entry.remote,
 93→			projects: entry.projects,
 94→			totalSessions: entry.projects.reduce((s, p) => s + p.sessionCount, 0),
 95→			containsCwd,
 96→		});
 97→	}
 98→
 99→	// Second pass: match ungrouped projects to existing groups by path similarity.
100→	const homeSegments = homedir().split("/").length;
101→	const remainingUngrouped: ScannedProject[] = [];
102→
103→	for (const project of ungrouped) {
104→		const match = findBestGroupByPath(project, groups, homeSegments);
105→		if (match) {
106→			match.projects.push(project);
107→			match.totalSessions += project.sessionCount;
108→			if (
109→				cwd === project.projectPath ||
110→				cwd.startsWith(`${project.projectPath}/`)
111→			) {
112→				match.containsCwd = true;
113→			}
114→		} else {
115→			remainingUngrouped.push(project);
116→		}
117→	}
118→
119→	for (const project of remainingUngrouped) {
120→		const containsCwd =
121→			cwd === project.projectPath || cwd.startsWith(`${project.projectPath}/`);
122→		groups.push({
123→			displayName: project.displayPath,
124→			gitRemote: null,
125→			projects: [project],
126→			totalSessions: project.sessionCount,
127→			containsCwd,
128→		});
129→	}
130→
131→	groups.sort((a, b) => {
132→		if (a.containsCwd !== b.containsCwd) return a.containsCwd ? -1 : 1;
133→		const aHasRemote = a.gitRemote !== null;
134→		const bHasRemote = b.gitRemote !== null;
135→		if (aHasRemote !== bHasRemote) return aHasRemote ? -1 : 1;
136→		return a.displayName.localeCompare(b.displayName);
137→	});
138→
139→	// Fire-and-forget cache write
140→	if (cacheUpdated) {
141→		cacheRemotes(cache);
142→	}
143→
144→	return groups;
145→}
