147→function commonPrefixLength(a: string, b: string): number {
148→	const partsA = a.split("/");
149→	const partsB = b.split("/");
150→	let count = 0;
151→	for (let i = 0; i < Math.min(partsA.length, partsB.length); i++) {
152→		if (partsA[i] === partsB[i]) count++;
153→		else break;
154→	}
155→	return count;
156→}
157→
158→function findBestGroupByPath(
159→	project: ScannedProject,
160→	groups: ProjectGroup[],
161→	homeSegments: number,
162→): ProjectGroup | null {
163→	let bestGroup: ProjectGroup | null = null;
164→	let bestLen = 0;
165→	let secondBestLen = 0;
166→
167→	for (const group of groups) {
168→		if (!group.gitRemote) continue;
169→
170→		let groupBest = 0;
171→		for (const p of group.projects) {
172→			groupBest = Math.max(
173→				groupBest,
174→				commonPrefixLength(project.projectPath, p.projectPath),
175→			);
176→		}
177→
178→		if (groupBest > bestLen) {
179→			secondBestLen = bestLen;
180→			bestLen = groupBest;
181→			bestGroup = group;
182→		} else if (groupBest > secondBestLen) {
183→			secondBestLen = groupBest;
184→		}
185→	}
186→
187→	// Must extend beyond home dir AND be strictly better than second-best
188→	if (bestGroup && bestLen > homeSegments && bestLen > secondBestLen) {
189→		return bestGroup;
190→	}
191→	return null;
192→}
